import React from 'react';
import { useEffect } from 'react';
import { createUserWithEmailAndPassword } from 'firebase/auth';
import { setDoc, doc } from 'firebase/firestore';
import { auth, db } from './firebase/config';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './pages/Login';
import PlayerDashboard from './pages/PlayerDashboard';
import AdminDashboard from './pages/AdminDashboard';
import AdminSetup from './pages/AdminSetup';
import './App.css';

const ProtectedRoute = ({ children, adminOnly = false }) => {
  const { user, playerData } = useAuth();
  if (!user) return <Navigate to="/login" />;
  if (adminOnly && !playerData?.isAdmin) return <Navigate to="/dashboard" />;
  return children;
};

function AppRoutes() {
  const { user, playerData } = useAuth();
  return (
    <Routes>
      <Route path="/login" element={!user ? <Login /> : <Navigate to={playerData?.isAdmin ? "/admin" : "/dashboard"} />} />
      <Route path="/dashboard" element={<ProtectedRoute><PlayerDashboard /></ProtectedRoute>} />
      <Route path="/admin" element={<ProtectedRoute adminOnly><AdminDashboard /></ProtectedRoute>} />
      <Route path="/admin/setup" element={<ProtectedRoute adminOnly><AdminSetup /></ProtectedRoute>} />
      <Route path="*" element={<Navigate to={user ? (playerData?.isAdmin ? "/admin" : "/dashboard") : "/login"} />} />
    </Routes>
  );
}

export default function App() {


useEffect(() => {
    async function createAdmin() {
      try {
        const cred = await createUserWithEmailAndPassword(
          auth,
          "admin@bccircle.com",
          "Admin@12345"
        );

        await setDoc(doc(db, "players", cred.user.uid), {
          name: "Admin",
          email: "admin@bccircle.com",
          isAdmin: true,
          hasWon: true,
          wonMonth: null,
          createdAt: new Date().toISOString()
        });

        console.log("✅ Admin created:", cred.user.uid);
      } catch (err) {
        console.log("❌", err.message);
      }
    }

    createAdmin();
  }, []);

  return (
    <BrowserRouter>
      <AuthProvider>
        <Toaster position="top-center" toastOptions={{
          style: { background: '#1a1a2e', color: '#e8d5b7', border: '1px solid #c9a84c' },
          duration: 3000
        }} />
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
}
